/**
 * Optional: a minimal custom tab based OAuth2 Authorization Code + PKCE helper skeleton.
 * Requires a backend to exchange the authorization code for tokens.
 */
object OAuthPkce {
    data class AuthRequest(
        val authorizationEndpoint: String,
        val clientId: String,
        val redirectUri: String,
        val scope: String,
        val state: String,
        val codeChallenge: String,
        val codeChallengeMethod: String = "S256",
        val extras: Map<String, String> = emptyMap()
    )

    fun buildAuthUri(req: AuthRequest): Uri {
        val b = Uri.parse(req.authorizationEndpoint).buildUpon()
            .appendQueryParameter("response_type", "code")
            .appendQueryParameter("client_id", req.clientId)
            .appendQueryParameter("redirect_uri", req.redirectUri)
            .appendQueryParameter("scope", req.scope)
            .appendQueryParameter("state", req.state)
            .appendQueryParameter("code_challenge", req.codeChallenge)
            .appendQueryParameter("code_challenge_method", req.codeChallengeMethod)

        for ((k, v) in req.extras) b.appendQueryParameter(k, v)
        return b.build()
    }
}

